#include <bits/stdc++.h>
using namespace std;

const int N=6e5+10;

int n,m,sa[N],x[N],y[N],c[N],rk[N],height[N];
char s[N];

void get_sa(){
    m=26;
    for(int i=1;i<=n;i++) c[x[i]=s[i]-'a'+1]++;
    for(int i=2;i<=m;i++) c[i]+=c[i-1];
    for(int i=n;i;i--) sa[c[x[i]]--]=i;
    int num;
    for(int k=1;k<=n;k<<=1){
        num=0;
        for(int i=n-k+1;i<=n;i++) y[++num]=i;
        for(int i=1;i<=n;i++)
            if(sa[i]>k) y[++num]=sa[i]-k;
        for(int i=1;i<=m;i++) c[i]=0;
        for(int i=1;i<=n;i++) c[x[i]]++;
        for(int i=2;i<=m;i++) c[i]+=c[i-1];
        for(int i=n;i;i--) sa[c[x[y[i]]]--]=y[i],y[i]=0;
        swap(x,y);
        x[sa[1]]=num=1;
        for(int i=2;i<=n;i++)
            x[sa[i]]=((y[sa[i]]==y[sa[i-1]] && y[sa[i]+k]==y[sa[i-1]+k])?num:++num);
        if(num==n) break;
        m=num;
    }
}

void get_height(){
    for(int i=1;i<=n;i++) rk[sa[i]]=i;
    for(int i=1,k=0;i<=n;i++){
        if(rk[i]==1){
            height[rk[i]]=k=0;
            continue;
        }
        k=max(0,k-1);
        int j=sa[rk[i]-1];
        while(i+k<=n && j+k<=n && s[i+k]==s[j+k]) k++;
        height[rk[i]]=k;
    }
}

int main(){
    scanf("%s",s+1);
    n=strlen(s+1);
    get_sa();
    get_height();
    for(int i=1;i<=n;i++)
        printf("%d ",sa[i]-1);
    puts("");
    for(int i=1;i<=n;i++)
        printf("%d ",height[i]);
    return 0;
}
